import express from 'express';
import { Autumn } from 'autumn-js';

const app = express();
app.use(express.json());

const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

// POST /workspaces â€” Create a workspace entity in Autumn
app.post('/workspaces', async (req, res) => {
  try {
    const { workspaceId, customerId, name, featureId = 'credits' } = req.body;

    if (!workspaceId || !customerId) {
      return res.status(400).json({ error: 'workspaceId and customerId are required' });
    }

    const entity = await autumn.entities.create({
      entityId: workspaceId,
      customerId,
      featureId,
      name,
    });

    res.status(201).json(entity);
  } catch (error) {
    res.status(500).json({ error: error.message || 'Failed to create workspace' });
  }
});

// POST /workspaces/:workspaceId/use-credits â€” Check and consume workspace credits
app.post('/workspaces/:workspaceId/use-credits', async (req, res) => {
  try {
    const { workspaceId } = req.params;
    const { amount = 1, featureId = 'credits' } = req.body;

    // First get the entity to find its customerId
    const entity = await autumn.entities.get({ entityId: workspaceId });

    if (!entity || !entity.customerId) {
      return res.status(404).json({ error: 'Workspace not found or missing customerId' });
    }

    const checkResponse = await autumn.check({
      customerId: entity.customerId,
      entityId: workspaceId,
      featureId: entity.featureId || featureId,
      requiredBalance: amount,
      sendEvent: true,
    });

    res.json(checkResponse);
  } catch (error) {
    res.status(500).json({ error: error.message || 'Failed to use credits' });
  }
});

// GET /workspaces/:workspaceId/balance â€” Fetch workspace entity balance
app.get('/workspaces/:workspaceId/balance', async (req, res) => {
  try {
    const { workspaceId } = req.params;

    const entity = await autumn.entities.get({ entityId: workspaceId });

    if (!entity) {
      return res.status(404).json({ error: 'Workspace not found' });
    }

    res.json({ balances: entity.balances });
  } catch (error) {
    res.status(500).json({ error: error.message || 'Failed to get balance' });
  }
});

// DELETE /workspaces/:workspaceId â€” Delete a workspace entity
app.delete('/workspaces/:workspaceId', async (req, res) => {
  try {
    const { workspaceId } = req.params;

    await autumn.entities.delete({ entityId: workspaceId });

    res.status(204).send();
  } catch (error) {
    res.status(500).json({ error: error.message || 'Failed to delete workspace' });
  }
});

const PORT = 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

